const fmtDate = new Intl.DateTimeFormat('ja-JP', { timeZone: 'Asia/Tokyo', month: '2-digit', day: '2-digit', weekday: 'short' });
const fmtTime = value => {
  if (!value) return '終日';
  const d = new Date(value);
  if (Number.isNaN(d.getTime())) return '終日';
  return new Intl.DateTimeFormat('ja-JP', { timeZone: 'Asia/Tokyo', hour: '2-digit', minute: '2-digit' }).format(d);
};
const today = fmtDate.format(new Date());
const events = $items("Get Today's Calendar Events").map(item => item.json || {}).filter(e => e.summary || e.start || e.end).sort((a, b) => String(a.start?.dateTime || a.start?.date || '').localeCompare(String(b.start?.dateTime || b.start?.date || '')));
const priorityRank = { S: 0, A: 1, B: 2, C: 3 };
const priorityOf = title => {
  const m = String(title || '').match(/^\[([SABC])\]/i);
  return m ? m[1].toUpperCase() : 'B';
};
const cleanTitle = title => String(title || '(no title)').replace(/^\[[SABC]\]\s*/i, '');
const dueRank = due => {
  if (!due) return 3;
  const d = new Date(due);
  if (Number.isNaN(d.getTime())) return 2;
  const todayKey = new Intl.DateTimeFormat('en-CA', { timeZone: 'Asia/Tokyo' }).format(new Date());
  const dueKey = new Intl.DateTimeFormat('en-CA', { timeZone: 'Asia/Tokyo' }).format(d);
  return dueKey <= todayKey ? 0 : 1;
};
const tasks = items.map(item => item.json || {}).filter(t => String(t.status || 'needsAction') !== 'completed' && (t.title || t.id)).sort((a, b) => (priorityRank[priorityOf(a.title)] ?? 2) - (priorityRank[priorityOf(b.title)] ?? 2) || dueRank(a.due) - dueRank(b.due)).slice(0, 3);
let text = `*Morning Check - ${today}*\n`;
text += '\n*Today\'s Events*\n';
if (events.length === 0) {
  text += 'No events today.\n';
} else {
  text += events.slice(0, 8).map((e, i) => {
    const start = e.start?.dateTime || e.start?.date;
    const end = e.end?.dateTime || e.end?.date;
    const time = start && end ? `${fmtTime(start)}-${fmtTime(end)}` : fmtTime(start);
    const where = e.location ? ` @ ${e.location}` : '';
    return `${i + 1}. ${time} ${e.summary || '(untitled)'}${where}`;
  }).join('\n') + '\n';
}
text += '\n*Top 3 Tasks*\n';
if (tasks.length === 0) {
  text += 'No open tasks.';
} else {
  text += tasks.map((t, i) => {
    const p = priorityOf(t.title);
    const due = t.due ? ` / due: ${fmtDate.format(new Date(t.due))}` : '';
    return `${i + 1}. [${p}] ${cleanTitle(t.title)}${due}`;
  }).join('\n');
}
return [{ json: { text, event_count: events.length, task_count: tasks.length } }];
